data <- data.frame(N0 = N0_values, Epsilon = Epsilon_values)

# Fit a linear model
linear_model <- lm(Epsilon ~ N0, data=data)
summary(linear_model)

# Fit a polynomial model (quadratic)
poly_model <- lm(Epsilon ~ poly(N0, 2), data=data)
summary(poly_model)

# Fit a logarithmic model
log_model <- lm(Epsilon ~ log(N0), data=data)
summary(log_model)

# Fit an exponential model after log transormation
exp_model <- lm(log(Epsilon) ~ N0, data=data)
summary(exp_model)

# Fit a power law model by log-transforming both variables
power_model <- lm(log(Epsilon) ~ log(N0), data=data)
summary(power_model)

# Fit a non-linear model (example with a power law)
nls_model <- nls(Epsilon ~ I(a * N0^b), data=data, start=list(a=.25, b=0.8))
summary(nls_model)

# Compare models using Akaike Information Criterion
aic_values <- AIC(linear_model, poly_model, log_model, exp_model, power_model, nls_model)
print(aic_values)

# Compare models using Bayesian Information Criterion
bic_values <- BIC(linear_model, poly_model, log_model, exp_model, power_model, nls_model)
print(bic_values)

# Plot the data and the fits
plot(data$N0, data$Epsilon, main="Fitted Models", xlab="N0", ylab="Epsilon", pch=19)

# Add linear model predictions
lines(data$N0, predict(linear_model, newdata=data), col="blue")

# Add polynomial model predictions
lines(data$N0, predict(poly_model, newdata=data), col="green")

# Exponential predictions
exp_predictions <- exp(predict(exp_model, newdata=data))
lines(sort(data$N0), exp_predictions[order(data$N0)], col="orange")

# Power law predictions (using the nls model directly)
power_predictions <- predict(nls_model, newdata=data)
lines(sort(data$N0), power_predictions[order(data$N0)], col="red")

# Add a legend
legend("topright", legend=c("Linear", "Polynomial", "Exponential", "Power Law"),
       col=c("blue", "green", "orange", "red"), lty=1, cex=0.8)
